module RefModule(clk, Reset, PCWre, nextAddress, Address);input clk, Reset, PCWre;
    input [31:0] nextAddress;
    output reg [31:0] Address;
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk)begin
        if (Reset == 0)
            Address = 0;
        else if(PCWre==1)
            Address = nextAddress;
    end
endmodule
